import sys

sys.stdin = open('input.txt', 'r')
sys.stdout = open('output.txt', 'w')


def is_palindrome(num):
    return str(num) == str(num)[::-1]


def is_zcy(num):
    return len(str(num)) % 2 == 0 and is_palindrome(num)


k, p = map(int, input().split())

zcy_nums = []
i = 1
while len(zcy_nums) < k:
    if is_zcy(i):
        zcy_nums.append(i)
    i += 1

print(sum(zcy_nums) % p)


